// 工具函数：设置按钮样式
function setButtonStyle(button, isNormal) {
    if (isNormal) {
        if (button === 批量停止按钮) {
            button.$el.children[0].style.background = "#FFE3E3"; // 红色背景
        } else {
            button.$el.children[0].style.background = "#F1F4FF"; // 蓝色背景
        }
        button.disabled = false;
    } else {
        button.$el.children[0].style.background = "#A4ABBC"; // 灰色背景
        button.disabled = true;
    }
}

setButtonStyle(批量部署按钮, true);
setButtonStyle(批量撤销部署按钮, true);
setButtonStyle(批量启动按钮, true);
setButtonStyle(批量停止按钮, true);

let labelName = 页面切换按钮栏.GetCheckedText();

//页面名称
let pageName = labelName + "_页面";
$Variable.currentPageName = pageName;
//配置自定义参数:设置公开变量初值和关联预定义
let options = {
    variables: [{
        name: "spaceTimeObjectFullPath",
        value: $Variable.配置时空对象全路径
    }, {
        name: "spaceTimeObjectName",
        value: $Variable.配置后台对象名称
    }, {
        name: "cloudID",
        value: $Variable.cloudID
    }, {
        name: "projectRepositoryGUID",
        value: $Variable.工程时空仓库GUID
    }, {
        name: "rootRepositoryGUID",
        value: $Variable.工程Root时空仓库GUID
    }, {
        name: "selectCloudInfos",
        value: $Variable.selectCloudInfos
    }, {
        name: "cloudInfos",
        value: $Variable.cloudInfo
    }, {
        name: "areaID",
        value: $Variable.areaToID
    }, {
        name: "projectName",
        value: $Variable.工程时空仓库名称
    }]
};
let openRet = 页面展示分栏.setChild(pageName, options, function(res) {
    if ("SetVariable" === res.eventName) {
        $Variable[res.eventParam[1]] = res.eventParam[2];
    } else if ("GetVariable" === res.eventName) {
        $Variable[res.eventParam[1]] = !$Variable[res.eventParam[1]];
    }
});
console.log(openRet);

debugger

let undeployNodeCount = $Variable.selectedNodeStatus.undeployNodeCount;
let deployedStartedCount = $Variable.selectedNodeStatus.deployedStartedCount; // 已部署且已启动
let deployedStoppedCount = $Variable.selectedNodeStatus.deployedStoppedCount; // 已部署但未启动
let unnormalNodeCount =  $Variable.selectedNodeStatus.unnormalNodeCount;
let partDeployCount =  $Variable.selectedNodeStatus.partDeployCount; // 部分部署
// 计算总选择节点数和已部署节点数
const totalSelected = undeployNodeCount + deployedStartedCount + deployedStoppedCount + unnormalNodeCount + partDeployCount;
const deployNodeCount = deployedStartedCount + deployedStoppedCount;

// 工具函数：设置按钮样式
function setButtonStyle(button, isNormal) {
    if (isNormal) {
        if (button === 批量停止按钮) {
            button.$el.children[0].style.background = "#FFE3E3"; // 红色背景
        } else {
            button.$el.children[0].style.background = "#F1F4FF"; // 蓝色背景
        }
        button.disabled = false;
    } else {
        button.$el.children[0].style.background = "#A4ABBC"; // 灰色背景
        button.disabled = true;
    }
}

// 重置所有按钮状态为禁用
function disableAllButtons() {
    setButtonStyle(批量部署按钮, false);
    setButtonStyle(批量撤销部署按钮, false);
    setButtonStyle(批量启动按钮, false);
    setButtonStyle(批量停止按钮, false);
}

// 主逻辑
disableAllButtons();

// 情况1：全部未选择
if (totalSelected === 0) {
    setButtonStyle(批量部署按钮, true);
    setButtonStyle(批量撤销部署按钮, true);
    setButtonStyle(批量启动按钮, true);
    setButtonStyle(批量停止按钮, true);
}
// 情况6：选择多种状态
else if ((undeployNodeCount > 0 && (deployNodeCount > 0 || partDeployCount >0)) ||
    (deployedStartedCount > 0 && (deployedStoppedCount > 0 || partDeployCount > 0)) || unnormalNodeCount > 0) {
    // 所有按钮保持禁用状态
}
// 单一状态选择
else {
    // 情况2：只选择未部署
    if (undeployNodeCount > 0 && deployNodeCount === 0 && partDeployCount == 0) {
        setButtonStyle(批量部署按钮, true);
    }
    // 情况3和5：只选择已部署且全部未启动
    else if (deployedStoppedCount > 0 && deployedStartedCount === 0 && partDeployCount == 0) {
        setButtonStyle(批量撤销部署按钮, true);
        setButtonStyle(批量启动按钮, true);
    }
    // 情况4：只选择已部署且全部已启动
    else if (deployedStartedCount > 0 && deployedStoppedCount === 0) {
        setButtonStyle(批量停止按钮, true);
    } else if(partDeployCount > 0 && deployedStartedCount == 0){
        setButtonStyle(批量撤销部署按钮, true);
    }
}

/*
 * 创建人：tian.he
 * 函数名：queryCloudRegionsList
 * 描述：查询云区域列表
 * 步骤：
 * 参数：
 * 返回值：
 */

debugger

// 声明call函数常量
const CALL_BY_NAME = 2;
const API_TYPE = 21001; // 接口类型标识
const TIMEOUT = 1000 * 60 * 5; // 接口请求超时时间
const PARAM_PUBLIC = new StringMap({
    "cloudID": $Variable.cloudID,
    "type": API_TYPE,
    "timeout": TIMEOUT
});
let cloudregionsArr = [];

// 消息提示窗
function _Infor(massage, type) {
    var options = {
        message: massage,
        type: type,
        duration: 3000,
        showClose: true
    };
    ShowMessage(options);
}

// 获取云区域列表函数
function _QueryCloudRegionsList() {

    const input = new StringMap({
        identifierType: CALL_BY_NAME,
        name: $Variable.配置后台对象名称,
        funcname: "IQueryCloudRegionsList",
        params: []
    });

    let pjtMngSTFullPath = $Variable.配置时空对象全路径;
    let runInfo = {
        stType: 5, // FULLNAME，使用全路径名标识，其他标识参数无效
        spaceTime: pjtMngSTFullPath // 目标页面的时空属性，和sTType配合使用
    }
    SetRunInfo(runInfo, async function(resData) {
        if (0 === resData.ret) {

            let res = await Call(PARAM_PUBLIC, input);

            try {
                if (0 !== res.ret) {
                    let errormsg = "请求发送失败！请检查后台服务是否运行正常";
                    _Infor(errormsg, "error");
                    console.log("-E- " + errormsg + "，ret:", res.ret);
                    return -1;
                }

                if (res.errorcodes) {
                    for (let i = 0; i < res.errorcodes.length; i++) {
                        let res_errorcode = res.errorcodes[i];
                        if (0 !== res_errorcode) {
                            _Infor("查询云区域列表失败！", "error");
                            console.log("-E- IQueryCloudRegionsList()接口错误，errorCode:", res_errorcode);
                            return -1;
                        }
                    }
                }

                if (res.returndata) {
                    let res_returndata = res.returndata;
                    if (0 !== res_returndata.errorcode) {
                        _Infor("查询云区域列表失败！", "error");
                        console.log(res_returndata.errormsg);
                        return -1;
                    }
                    // 解析数据
                    $Variable.areaToID = res_returndata.areatoid;
                    let cloudregionslist = res_returndata.cloudregionslist || [];
                    for (let i = 0; i < cloudregionslist.length; i++) {
                        let cloudregionitem = cloudregionslist[i];
                        // 设置本云信息
                        if (!cloudregionitem.isaddcloud) {
                            cloudregionsArr[0].id = `${i}`;
                            cloudregionsArr[0].cloudRegionInfo = {
                                isaddcloud: cloudregionitem.isaddcloud,
                                guid: cloudregionitem.guid
                            };
                            // 设置全局变量
                            $Variable.localCloudInfos = cloudregionsArr[0].cloudRegionInfo;
                        } else {
                            // 设置子云信息
                            let cloudregionsobj = {
                                header: {
                                    leftText: cloudregionitem.name,
                                    rightText: cloudregionitem.connectstatus
                                },
