function extractIP(url) {
    try {
        // 方法1：正则表达式（首选）
        const ipRegex = /\d{1,3}(\.\d{1,3}){3}/;
        const match = url.match(ipRegex);

        if (match && match[0]) {
            return match[0];
        }

        // 方法2：备用方案（URL API）
        if (typeof URL === 'function') {
            return new URL(url).hostname;
        }
    } catch (e) {
        console.error("IP提取失败:", e);
    }
    return "127.0.0.1";
}

function main() {
    // 获取本云IP
    let urlStr = location.href.split("GetFileContent")[0];
    let currentIp = extractIP(urlStr);
    cloudregionsArr.push({
